package org.apache.commons.math3.optimization.general;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math3.optimization.general.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.math3.optimization.general.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.analysis.ParametricUnivariateFunction;
import org.apache.commons.math3.optimization.general.LevenbergMarquardtOptimizer;
import org.apache.commons.math3.optimization.fitting.HarmonicOscillator;
import org.apache.commons.math3.optimization.fitting.PolynomialFitter;
import org.apache.commons.math3.optimization.fitting.WeightedObservedPoint;
import org.apache.commons.math3.util.FastMath;

import java.util.Random;

import static org.junit.Assert.*;

public class StepDefs {

    private double[] originalCoefficients;
    private WeightedObservedPoint[] dataset;
    private double[] fittedCoefficients;

    @Given("a random polynomial of degree 9")
    public void a_random_polynomial_of_degree_9() {
        Random random = new Random(123456789L);
        originalCoefficients = new double[10];
        for (int i = 0; i < 10; i++) {
            originalCoefficients[i] = random.nextDouble() * 10 - 5; // Random coefficients between -5 and 5
        }
    }

    @Given("a dataset of 40000 points generated from this polynomial with noise")
    public void a_dataset_of_points_generated_from_this_polynomial_with_noise() {
        dataset = new WeightedObservedPoint[40000];
        Random random = new Random(123456789L);

        // Create a polynomial function from the coefficients
        class PolynomialFunction implements ParametricUnivariateFunction {
            @Override
            public double value(double x, double... parameters) {
                double result = 0;
                for (int i = 0; i < parameters.length; i++) {
                    result += parameters[i] * FastMath.pow(x, i);
                }
                return result;
            }

            @Override
            public double[] gradient(double x, double... parameters) {
                double[] gradient = new double[parameters.length];
                for (int i = 0; i < parameters.length; i++) {
                    gradient[i] = FastMath.pow(x, i);
                }
                return gradient;
            }
        }

        PolynomialFunction polyFunc = new PolynomialFunction();

        for (int i = 0; i < dataset.length; i++) {
            double x = i * 0.001; // Spread x values
            double yTrue = polyFunc.value(x, originalCoefficients);
            double yNoisy = yTrue + (random.nextGaussian() * 0.01); // Add small noise
            dataset[i] = new WeightedObservedPoint(1.0, x, yNoisy);
        }
    }

    @Given("each point has a weight of 1.0, resulting in a diagonal weight matrix")
    public void each_point_has_a_weight_of_1_0_resulting_in_a_diagonal_weight_matrix() {
        // Weights are already set to 1.0 in the previous step
        // This step confirms that we have a diagonal weight matrix (which is the case when all weights are 1.0)
    }

    @When("I fit a polynomial to this dataset using the Levenberg-Marquardt optimizer")
    public void i_fit_a_polynomial_to_this_dataset_using_the_Levenberg_Marquardt_optimizer() {
        try {
            LevenbergMarquardtOptimizer optimizer = new LevenbergMarquardtOptimizer();
            PolynomialFitter fitter = new PolynomialFitter(optimizer);

            for (WeightedObservedPoint point : dataset) {
                fitter.addObservedPoint(point);
            }

            fittedCoefficients = fitter.fit(originalCoefficients.length);
        } catch (Exception e) {
            // Store the exception if needed for verification
            throw new RuntimeException("Polynomial fitting failed: " + e.getMessage(), e);
        }
    }

    @Then("the fitting process should complete successfully")
    public void the_fitting_process_should_complete_successfully() {
        assertNotNull("Fitted coefficients should not be null", fittedCoefficients);
        assertEquals("Should have the correct number of coefficients", originalCoefficients.length, fittedCoefficients.length);
    }

    @Then("the fitted polynomial coefficients should approximate the original polynomial")
    public void the_fitted_polynomial_coefficients_should_approximate_the_original_polynomial() {
        assertNotNull("Fitted coefficients should not be null", fittedCoefficients);
        assertEquals("Should have the correct number of coefficients", originalCoefficients.length, fittedCoefficients.length);

        // Compare coefficients with a reasonable tolerance
        for (int i = 0; i < originalCoefficients.length; i++) {
            double tolerance = Math.abs(originalCoefficients[i]) * 0.1; // 10% relative tolerance
            if (tolerance < 0.01) tolerance = 0.01; // Minimum absolute tolerance
            assertEquals("Coefficient " + i + " should be approximately correct", 
                        originalCoefficients[i], fittedCoefficients[i], tolerance);
        }
    }
}

